void run_all_telemetry_tests(ring_buffer_t *rb) {
    run_test_batch_0_to_100(rb);
    run_test_batch_100_to_200(rb);
    run_test_batch_200_to_300(rb);
    run_test_batch_300_to_400(rb);
    run_test_batch_400_to_500(rb);
}

int main() {
    printf("==================================================\n");
    printf("PHASR Phase-3: Invariant Drift & Telemetry Monitor\n");
    printf("Target Engine: C Telemetry Collector (Emulated eBPF + Assembly)\n");
    printf("==================================================\n\n");

    ring_buffer_t rb;
    init_ring_buffer(&rb);

    printf("[1/2] Running %d Invariant Telemetry Assertions...\n", NUM_TEST_CASES);
    run_all_telemetry_tests(&rb);
    printf("      Assertions Run: %u\n", g_stats.total);
    printf("      Passed: %u | Failed: %u\n", g_stats.passed, g_stats.failed);
    
    if (g_stats.failed == 0) {
        printf("      SUCCESS: All invariants and attestation states verified successfully.\n\n");
    } else {
        printf("      WARNING: Validator failures detected in telemetry invariants!\n\n");
    }

    printf("[2/2] Running Cascading Failure Propagation Wave Simulation...\n");
    printf("      Equation: d^2(phi)/dt^2 + gamma * d(phi)/dt = v^2 * del^2(phi)\n");
    printf("      Theoretical Spatial Decay: alpha = (gamma * v) / 2 = %f\n\n", (WAVE_GAMMA * WAVE_COURANT) / 2.0f);

    wave_sim_t sim;
    init_wave_sim(&sim);

    printf("  --- Telemetry Wave Edge Cases Assertions ---\n");
    step_wave_sim(&sim, 0.0f);
    step_wave_sim(&sim, -0.5f);
    printf("  --------------------------------------------\n\n");

    float dt = 0.1f;
    for (int step = 0; step < 30; step++) {
        step_wave_sim(&sim, dt);
        if (step % 3 == 0) {
            print_wave_profile(&sim);
            printf("\n");
        }
    }

    printf("Wave simulation telemetry sequence complete.\n");
    printf("==================================================\n");
    return g_stats.failed == 0 ? 0 : 1;
}
